// src/components/Settings.js
import React, { useState } from "react";
import StudentTimetable from "./StudentTimetable"; // Import the student timetable component

const Settings = () => {
  const [view, setView] = useState(null); // Track the current panel
  const [timetableAction, setTimetableAction] = useState(null); // Track which action is selected in Student Timetable

  const handleEnterAdminPanel = () => {
    setView("adminPanel");
    setTimetableAction(null); // Reset timetable view
  };

  const handleEnterStudentTimetable = () => {
    setView("studentTimetable");
    setTimetableAction(null); // Reset timetable view
  };

  const handleLogout = () => {
    setView(null);
    setTimetableAction(null);
  };

  return (
    <div className="admin-panel-wrapper">
      {!view && (
        <>
          {/* Admin Panel Button */}
          <div className="admin-panel duplicated">
            <h3>Admin Panel</h3>
            <p>Modify Admin Password and Update Admin Data.</p>
            <button className="settings-button" onClick={handleEnterAdminPanel}>ENTER</button>
          </div>

          {/* Student Timetable Panel Button */}
          <div className="admin-panel">
            <h3>Student Timetable Panel</h3>
            <p>Modify Student Timetable and Allocated Rooms</p>
            <button className="settings-button" onClick={handleEnterStudentTimetable}>ENTER</button>
          </div>
        </>
      )}

      {/* Admin Panel Content */}
      {view === "adminPanel" && (
        <div className="admin-panel-content">
          <h3>Welcome to the Admin Panel!</h3>
          <p>Here you can manage admin settings.</p>
          {/* Add components for modifying admin password */}
          <button className="back-button" onClick={handleLogout}>Back</button>
        </div>
      )}

      {/* Student Timetable Panel Content */}
      {view === "studentTimetable" && (
        <div className="student-timetable-content">
          <h3>Student Timetable</h3>
          <p>Select an action to modify the student timetable.</p>
          
          {/* Student Timetable Actions */}
          <div className="timetable-actions">
            <button onClick={() => setTimetableAction("add")}>Add New Timetable</button>
            <button onClick={() => setTimetableAction("edit")}>Edit Timetable</button>
            <button onClick={() => setTimetableAction("update")}>Update Timetable</button>
            <button onClick={() => setTimetableAction("delete")}>Delete Timetable</button>
          </div>

          {/* Render Timetable Actions Based on Selection */}
          {timetableAction === "add" && <div><h4>Add New Timetable</h4><p>Form to add a new timetable goes here.</p></div>}
          {timetableAction === "edit" && <div><h4>Edit Timetable</h4><p>Form to edit an existing timetable.</p></div>}
          {timetableAction === "update" && <div><h4>Update Timetable</h4><p>Form to update timetable entries.</p></div>}
          {timetableAction === "delete" && <div><h4>Delete Timetable</h4><p>Form to delete timetable records.</p></div>}

          {/* Back Button */}
          <button className="back-button" onClick={handleLogout}>Back</button>
        </div>
      )}
    </div>
  );
};

export default Settings;
